insert into order_payment (
    payment_no, order_no, user_id, amount, pay_channel, pay_status, transaction_no, callback_payload, fail_reason, paid_time
) values (
    #{paymentNo}, #{orderNo}, #{userId}, #{amount}, #{payChannel}, #{payStatus}, #{transactionNo}, #{callbackPayload}, #{failReason},
    case when #{payStatus} = '1' then sysdate() else null end
)
